def parse_nested_parens(paren_string: str) -> List[int]:
    groups = [g for g in paren_string.split(' ') if g]
    result = []
    for group in groups:
        max_depth = 0
        current_depth = 0
        for char in group:
            if char == '(':
                current_depth += 1
                if current_depth > max_depth:
                    max_depth = current_depth
            elif char == ')':
                current_depth -= 1
        result.append(max_depth)
    return result

