def encode(message):
    vowels = set('aeiouAEIOU')
    result = []
    for ch in message:
        if ch.isalpha():
            # Step 1: swap case
            swapped = ch.swapcase()
            # Step 2: if swapped char is a vowel, shift by 2
            if swapped in vowels:
                shifted = chr(ord(swapped) + 2)
                result.append(shifted)
