def minPath(grid, k):
    n = len(grid)

    # Find the position of value 1 (the minimum value)
    start_r, start_c = 0, 0
    for r in range(n):
        for c in range(n):
            if grid[r][c] == 1:
                start_r, start_c = r, c
                break

    # Find the minimum neighbor value of the cell containing 1
    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]
    min_neighbor = float('inf')
    for dr, dc in directions:
        nr, nc = start_r + dr, start_c + dc
        if 0 <= nr < n and 0 <= nc < n:
            min_neighbor = min(min_neighbor, grid[nr][nc])

    # Build the path: alternate between 1 and min_neighbor
    result = []
    for i in range(k):
        if i % 2 == 0:
            result.append(1)
        else:
            result.append(min_neighbor)

    return result

def tri(n):
    if n == 0:
        return [1]

    result = [1, 3]

    for i in range(2, n + 1):
        if i % 2 == 0:
            result.append(1 + i // 2)
        else:
            # tri(i) = tri(i-1) + tri(i-2) + tri(i+1)
            # Since i is odd, i+1 is even, so tri(i+1) = 1 + (i+1)/2
            tri_next = 1 + (i + 1) // 2
            result.append(result[i - 1] + result[i - 2] + tri_next)

    return result

